CREATE OR REPLACE FUNCTION public.block_manual_posted_transition()
RETURNS trigger LANGUAGE plpgsql AS $func$
BEGIN
  IF NEW.stage = 'posted' AND OLD.stage IS DISTINCT FROM NEW.stage THEN
    IF current_user NOT IN ('postgres', 'service_role', 'supabase_admin') THEN
      RAISE EXCEPTION 'POSTED_LOCKDOWN: ...';
    END IF;
    IF NEW.posted_at IS NULL THEN
      RAISE EXCEPTION 'POSTED_LOCKDOWN: stage="posted" requires posted_at to be non-null.';
    END IF;
  END IF;
  RETURN NEW;
END;
$func$;
